t.script:
(function() {
    const filter = document.getElementById('payslip_filter');
    const search = document.getElementById('payslip_search');
    const rows = document.querySelectorAll('#payslip_table tbody tr');

    function applyFilters() {
        const filterVal = filter.value;
        const searchVal = search.value.toLowerCase();
        rows.forEach(row => {
            const type = row.getAttribute('data-type');
            const text = row.getAttribute('data-text');
            const show = (filterVal === 'all' || type === filterVal) && (!searchVal || text.includes(searchVal));
            row.style.display = show ? '' : 'none';
        });
    }

    filter.addEventListener('change', applyFilters);
    search.addEventListener('input', applyFilters);
})();

div.script:
(function() {
    let lineCounter = 1;
    const container = document.getElementById('items_container');
    const addBtn = document.getElementById('add_item_line');
    const configSelect = document.getElementById('epp_config');
    const manualSection = document.getElementById('manual_items_section');
    const itemsPreview = document.getElementById('items_preview');

    // Agregar nueva línea de item
    addBtn.addEventListener('click', function() {
        const newLine = container.querySelector('.item-line').cloneNode(true);
        newLine.querySelectorAll('input, select').forEach(input => {
            const name = input.getAttribute('name');
            if (name) {
                input.setAttribute('name', name.replace(/line_\d+_/, `line_${lineCounter}_`));
                if (input.type === 'text' || input.type === 'number') {
                    input.value = input.type === 'number' ? '1' : '';
                }
            }
        });
        container.appendChild(newLine);
        lineCounter++;
    });

    // Eliminar línea
    container.addEventListener('click', function(e) {
        if (e.target.closest('.remove-line')) {
            if (container.querySelectorAll('.item-line').length > 1) {
                e.target.closest('.item-line').remove();
            } else {
                alert('Debe mantener al menos un item');
            }
        }
    });

    // Mostrar/ocultar sección manual según configuración
    configSelect.addEventListener('change', function() {
        if (this.value) {
            // Si hay configuración, ocultar items manuales y mostrar preview
            container.style.display = 'none';
            addBtn.style.display = 'none';
            itemsPreview.style.display = 'block';
        } else {
            // Si no hay configuración, mostrar items manuales
            container.style.display = 'block';
            addBtn.style.display = 'inline-block';
            itemsPreview.style.display = 'none';
        }
    });
})();

t.script:
document.addEventListener('DOMContentLoaded', function() {
    var iframe = document.getElementById('payslip_html_iframe');
    var loader = document.getElementById('payslip_loader');

    if (iframe && loader) {
        iframe.addEventListener('load', function() {
            loader.style.display = 'none';
            iframe.style.opacity = '1';
        });
    }
});
